module JohnsonCounter(  
    input clk,  
    input reset,  
    output reg [4:0] q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            q <= 5'b00000;  
        else  
            q <= {q[3:0], ~q[4]};  
    end  
endmodule
